INSERT INTO public.socios ("Id", "NombreEmpresa", "Slug", "Descripcion", "Especialidades", "Servicios", "RsWebsite", "RsFacebook", "RsLinkedin", "RsTwitter", "RsInstagram", "RsYoutube", "Telefono", "Direccion", "LogoUrl", "EmailContacto", "MapaUrl", "MarcasRepresenta", "EstadoFinanciero", "Habilitado", "CreatedAt", "UpdatedAt") VALUES ('eceb4567-b861-4412-8a2d-8610920b833e', 'INNOGEN CAPITAL', 'innogen-capital', 'Firma salvadoreña de capital de riesgo (Venture Capital) fundada en 2018, especializada en invertir en startups tecnológicas en etapas tempranas de Latinoamérica. Su enfoque principal está en empresas de alto crecimiento en sectores como FinTech, HealthTech, AgTech, PropTech, SaaS, E-Commerce e Inteligencia Artificial. Administra fondos de inversión enfocados en impulsar el ecosistema tecnológico de Centroamérica y Latinoamérica mediante capital inteligente, mentoría y conexiones estratégicas.', '{"Venture Capital",FinTech,HealthTech,AgTech,PropTech,SaaS,E-Commerce,"Inteligencia Artificial","Angel Investment","Portfolio Management"}', '{"Inversión en startups","Capital semilla","Venture Capital","Mentoría empresarial","Aceleración de empresas","Gestión de portafolios","Conexiones estratégicas para escalamiento"}', 'https://innogencapital.com/', '', 'https://www.linkedin.com/company/innogen-capital', '', '', '', '', 'San Salvador, El Salvador', 'https://media.licdn.com/dms/image/v2/D4E0BAQF8ElcF4KJE3A/company-logo_200_200/B4EZr_CjhoIoAI-/0/1765215451668/innogen_capital_logo?e=2147483647&v=beta&t=Ym0CjZGTKt2gl5yYvJCN2OZX8pkot186qxoTIrswKtc', 'info@innogencapital.com', '', '', 'AlDia', true, '2026-05-29 17:10:25.22739+00', '2026-05-29 17:10:25.22739+00');
