INSERT INTO public.socios ("Id", "NombreEmpresa", "Slug", "Descripcion", "Especialidades", "Servicios", "RsWebsite", "RsFacebook", "RsLinkedin", "RsTwitter", "RsInstagram", "RsYoutube", "Telefono", "Direccion", "LogoUrl", "EmailContacto", "MapaUrl", "MarcasRepresenta", "EstadoFinanciero", "Habilitado", "CreatedAt", "UpdatedAt") VALUES ('479c746b-77cf-4de2-9da1-d4538d96aae7', 'INSPIRETECH 1923', 'inspiretech-1923', 'Empresa salvadoreña especializada en transformación digital, innovación tecnológica y desarrollo de soluciones empresariales. Su enfoque está orientado a ayudar a las organizaciones a acelerar su adopción tecnológica mediante consultoría estratégica, automatización de procesos y desarrollo de soluciones digitales.', '{"Transformación Digital","Innovación Tecnológica","Consultoría IT","Automatización de Procesos","Desarrollo de Software","Estrategia Digital"}', '{"Consultoría tecnológica","Desarrollo de software","Automatización empresarial","Transformación digital","Gestión de proyectos tecnológicos","Innovación empresarial"}', 'https://inspiretech1923.com', '', 'https://www.linkedin.com/company/inspiretech1923', '', '', '', '', 'San Salvador, El Salvador', 'https://media.licdn.com/dms/image/v2/D560BAQF89UWQLpPw4g/company-logo_100_100/B56ZWnGYscHsAU-/0/1742265224365/inspiretech1923_logo?e=2147483647&v=beta&t=QrtMm7_VPxArTc4TON-Q_WeKoTJs6ca5ok8PK78moTY', 'info@inspiretech1923.com', 'https://www.google.com/maps/embed?pb=!1m18!1m12!1m3!1d304921.9165092816!2d-89.36699570008753!3d13.7108142186905!2m3!1f0!2f0!3f0!3m2!1i1024!2i768!4f13.1!3m3!1m2!1s0x8f6330bfffa34d4b%3A0x6de7f8f991e805e8!2sSan%20Salvador%20Centro!5e1!3m2!1ses!2ssv!4v1780074993962!5m2!1ses!2ssv', '', 'AlDia', true, '2026-05-29 17:20:04.335971+00', '2026-05-29 17:20:04.335971+00');
