INSERT INTO public.socios ("Id", "NombreEmpresa", "Slug", "Descripcion", "Especialidades", "Servicios", "RsWebsite", "RsFacebook", "RsLinkedin", "RsTwitter", "RsInstagram", "RsYoutube", "Telefono", "Direccion", "LogoUrl", "EmailContacto", "MapaUrl", "MarcasRepresenta", "EstadoFinanciero", "Habilitado", "CreatedAt", "UpdatedAt") VALUES ('ce40fc65-1da1-4f64-9a77-92d61ac4bbf9', 'EON Consultant', 'eon-consultant', 'Cualquiera puede crear un sitio web o gestionar cuentas en redes sociales, recibir el pago y pasar al siguiente cliente. Menos del 3% de los llamados expertos pueden hacer eso mientras entienden tu negocio y obtienen resultados medibles. Por eso trabajamos usando los avances tecnológicos y la la psicología humana para que los complejos procesos de crear, mantener o expandir tu negocio en línea se traduzcan en pasos simples que tu empresa pueda seguir.', '{"Business Development","Marketing Digital",SEO,SEM,Branding,"Desarrollo Web"}', '{"Consultoría empresarial","Desarrollo web","Gestión de redes sociales","Publicidad digital","Estrategia de marketing","Contenido digital"}', 'https://eonconsultant.com', 'https://www.facebook.com/eonconsultant', 'https://www.linkedin.com/company/eon-consultant', '', 'https://www.instagram.com/eonconsultant', '', '+506 2226-6550', 'Sector Los Sauces, San José, Provincia de San José, Costa Rica', 'https://eonconsultant.com/wp-content/uploads/2023/12/EON_1080X1080_Blue-150x150.png', '', '', '', 'AlDia', true, '2026-03-09 22:01:15.606427+00', '2026-03-11 16:24:52.483504+00');
