INSERT INTO public.socios ("Id", "NombreEmpresa", "Slug", "Descripcion", "Especialidades", "Servicios", "RsWebsite", "RsFacebook", "RsLinkedin", "RsTwitter", "RsInstagram", "RsYoutube", "Telefono", "Direccion", "LogoUrl", "EmailContacto", "MapaUrl", "MarcasRepresenta", "EstadoFinanciero", "Habilitado", "CreatedAt", "UpdatedAt") VALUES ('d57d8359-21d7-4e28-b9c3-ae56e9acb2c2', 'UNIVERSIDAD DE ORIENTE (UNIVO)', 'univo', 'Su actividad principal son los servicios educativos a nivel superior y se rige por la Ley de Educación Superior, su reglamento y demás leyes conexas: no pudieron intervenir en actividades religiosas o políticas de ninguna naturaleza. Sus funciones básicas son: la Docencia, Investigación y proyección social.', '{"Educación superior","Investigación académica","Formación profesional","Desarrollo académico","Proyección social"}', '{"Programas de educación superior","Carreras universitarias","Investigación académica","Actividades de proyección social","Formación profesional"}', 'https://www.univo.edu.sv', 'https://www.facebook.com/UNIVOSM', 'https://www.linkedin.com/school/universidad-de-oriente-sv-/', 'https://x.com/univosm', 'https://www.instagram.com/univosm/', 'https://www.youtube.com/@UNIVOSM', '7488-5902', ' 4ta Calle Poniente #705, San Miguel, El Salvador.', 'https://www.casatic.org/gallery\Socios\ae02162e-46e7-4499-9d62-12ce4ab6a73a.png ', 'info@univo.edu.sv', 'https://www.google.com/maps/embed?pb=!1m18!1m12!1m3!1d4769.013548142624!2d-88.1836557!3d13.4817728!2m3!1f0!2f0!3f0!3m2!1i1024!2i768!4f13.1!3m3!1m2!1s0x8f7b2a66689978cd%3A0x848a5908c440c41b!2sUniversidad%20de%20Oriente!5e1!3m2!1ses!2ssv!4v1776287621818!5m2!1ses!2ssv', '', 'AlDia', true, '2026-04-15 21:18:06.733475+00', '2026-04-15 21:18:06.733475+00');
INSERT INTO public.socios ("Id", "NombreEmpresa", "Slug", "Descripcion", "Especialidades", "Servicios", "RsWebsite", "RsFacebook", "RsLinkedin", "RsTwitter", "RsInstagram", "RsYoutube", "Telefono", "Direccion", "LogoUrl", "EmailContacto", "MapaUrl", "MarcasRepresenta", "EstadoFinanciero", "Habilitado", "CreatedAt", "UpdatedAt") VALUES ('c8b42b69-3e87-41d7-b23a-9aaf448995e0', 'UNIVERSIDAD FRANCISCO GAVIDIA', 'ufg', 'UFG está comprometida con una formación profesional de educación superior sustentada en tres pilares: Tecnología, ya que la sociedad de la Información y conocimiento funciona a escala global bajo paradigmas tecnológicos: Innovación, lo que supone utilizar al máximo las expresiones de imaginación y creatividad; y Calidad, como principio y fundamento de un quehacer académico que busca dar más de sí tras la excelencia.', '{"Educación superior",Tecnología,Innovación,"Formación profesional","Calidad académica"}', '{"Programas de pregrado","Programas académicos","Investigación académica","Educación continua","Formación profesional"}', 'https://ufg.edu.sv/', 'https://www.facebook.com/ufgoficial', 'https://www.linkedin.com/school/ufgoficial/', 'https://x.com/ufgoficial', 'https://www.instagram.com/ufg.oficial/', 'https://www.youtube.com/user/redsocialufg', '2209-2874', 'Calle El Progreso y Avenida Las Américas, San Salvador, El Salvador', 'https://www.casatic.org/gallery\Socios\a7520586-5f67-4e74-b92b-5f831a6cfd46.png ', 'contactcenter@ufg.edu.sv', 'https://www.google.com/maps/embed?pb=!1m18!1m12!1m3!1d4764.659055111902!2d-89.2224593240822!3d13.698283186688062!2m3!1f0!2f0!3f0!3m2!1i1024!2i768!4f13.1!3m3!1m2!1s0x8f6330449b49107b%3A0xb739e2c73c1004f6!2sUniversidad%20Francisco%20Gavidia!5e1!3m2!1ses!2ssv!4v1776784793550!5m2!1ses!2ssv', '', 'AlDia', true, '2026-04-21 15:16:55.304327+00', '2026-04-21 15:20:07.454081+00');
INSERT INTO public.socios ("Id", "NombreEmpresa", "Slug", "Descripcion", "Especialidades", "Servicios", "RsWebsite", "RsFacebook", "RsLinkedin", "RsTwitter", "RsInstagram", "RsYoutube", "Telefono", "Direccion", "LogoUrl", "EmailContacto", "MapaUrl", "MarcasRepresenta", "EstadoFinanciero", "Habilitado", "CreatedAt", "UpdatedAt") VALUES ('3419ef5f-ca3f-4c28-8832-97f8c1971d4f', 'UNIVERSIDAD GERARDO BARRIOS', 'ugb', 'Fundada por hombres y mujeres emprendedores, quienes se asociaron y formaron EMPRESA, (Empresarios migueleños para la Educación S.A.), creando la Sede Central de la Universidad el 05 de diciembre de 1981, la cual está ubicada en las instalaciones de la casa donde nació Juan José Cañas.', '{"Educación superior","Formación profesional","Investigación académica","Desarrollo académico","Proyección social"}', '{"Programas de pregrado","Programas académicos","Investigación universitaria","Educación continua","Formación profesional"}', 'https://www.ugb.edu.sv/', 'https://www.facebook.com/ugb.edu.sv', 'https://www.linkedin.com/school/universidad-gerardo-barrios', '', 'https://www.instagram.com/ugb_sv', 'https://www.youtube.com/@UGBsv', '2645-6500', 'calle Las Flores y Avenida Las Magnolias Colonia Escolán. San Miguel.', 'https://www.casatic.org/gallery\Socios\f8d0678d-4c52-4735-840f-e44f4be6af98.png ', 'rectoria@ugb.edu.sv', 'https://www.google.com/maps/embed?pb=!1m18!1m12!1m3!1d4768.87651918889!2d-88.19213289999999!3d13.488637999999998!2m3!1f0!2f0!3f0!3m2!1i1024!2i768!4f13.1!3m3!1m2!1s0x8f7b2a58d2095515%3A0xfb0914d1181e605f!2sUniversidad%20Gerardo%20Barrios!5e1!3m2!1ses!2ssv!4v1776785126650!5m2!1ses!2ssv', '', 'AlDia', true, '2026-04-21 15:25:34.10215+00', '2026-04-21 15:25:34.10215+00');
INSERT INTO public.socios ("Id", "NombreEmpresa", "Slug", "Descripcion", "Especialidades", "Servicios", "RsWebsite", "RsFacebook", "RsLinkedin", "RsTwitter", "RsInstagram", "RsYoutube", "Telefono", "Direccion", "LogoUrl", "EmailContacto", "MapaUrl", "MarcasRepresenta", "EstadoFinanciero", "Habilitado", "CreatedAt", "UpdatedAt") VALUES ('c672b414-1f55-4337-b438-2986181e16ea', 'UNIVERSIDAD PEDAGOGICA DE EL SALVADOR ''DR. LUIS ALONSO APARICIO''', 'pedagogica', 'Una Universidad capaz de contribuir al desarrollo humano sostenible del país por medio de la cooperación con los sectores involucrados; dispuesta a fomentar la comprensión y la tolerancia; comprometida con la difusión y popularización del conocimiento y la cultura; con la práctica de la investigación científica e innovación tecnológica.', '{"Educación superior","Formación docente","Investigación científica","Innovación tecnológica","Desarrollo humano"}', '{"Programas de pregrado","Programas académicos","Investigación universitaria","Educación continua","Formación profesional"}', 'https://www.pedagogica.edu.sv/', 'https://www.facebook.com/pedagogica', '', 'https://x.com/pedagogicaU', 'https://www.instagram.com/pedagogicasv', 'https://www.youtube.com/user/PedagogicaElSalvador', '2205 8100', '25 Av. Norte y Diagonal Hector Silva, San Salvador, San Salvador, El Salvador', 'https://www.casatic.org/gallery\Socios\7c988c21-f75b-4573-88a5-f84395fbda91.png ', 'info@pedagogica.edu.sv', 'https://www.google.com/maps/embed?pb=!1m12!1m8!1m3!1d1684.4953402608885!2d-89.20297029393872!3d13.707493239238802!3m2!1i1024!2i768!4f13.1!2m1!1suniversidad%20pedagogica!5e1!3m2!1ses!2ssv!4v1776785585234!5m2!1ses!2ssv', '', 'AlDia', true, '2026-04-21 15:33:14.530288+00', '2026-04-21 15:33:14.530288+00');
INSERT INTO public.socios ("Id", "NombreEmpresa", "Slug", "Descripcion", "Especialidades", "Servicios", "RsWebsite", "RsFacebook", "RsLinkedin", "RsTwitter", "RsInstagram", "RsYoutube", "Telefono", "Direccion", "LogoUrl", "EmailContacto", "MapaUrl", "MarcasRepresenta", "EstadoFinanciero", "Habilitado", "CreatedAt", "UpdatedAt") VALUES ('6ebd43d5-dbcf-4e9a-a5ca-f91d0c8c619c', 'UNIVERSIDAD SALVADOREÑA ALBERTO MASFERRER', 'usam', 'Fundada el 24 de noviembre de 1979 por un grupo visionario de profesionales en diferentes áreas, siendo la primera universidad privada que inclusionó en el área de salud, con carreras como Cirugía Dental, Medicina, Cirugía, Química y Farmacia, entre otras.', '{"Educación superior","Ciencias de la salud","Formación profesional","Investigación académica","Desarrollo académico"}', '{"Programas de pregrado","Carreras universitarias","Formación en salud","Investigación universitaria","Educación continua"}', 'https://www.usam.edu.sv/', 'https://www.facebook.com/usamelsalvador', 'https://www.linkedin.com/company/usamsv', 'https://x.com/usamelsalvador', 'https://www.instagram.com/usamelsalvador', 'https://www.youtube.com/c/USAM-ES', '2231-9600', '19 Av. Nte. entre 3 a Calle Pte. y Alameda Juan Pablo II, San Salvador, El Salvador.', 'https://www.casatic.org/gallery\Socios\ac87a842-f948-4c46-8107-64ac1f32ae41.png ', 'coordinadorcomputacion@usam.edu.sv', 'https://www.google.com/maps/embed?pb=!1m16!1m12!1m3!1d1191.1456421969567!2d-89.2011630732603!3d13.702056176204383!2m3!1f0!2f0!3f0!3m2!1i1024!2i768!4f13.1!2m1!1susam!5e1!3m2!1ses!2ssv!4v1776785956944!5m2!1ses!2ssv', '', 'AlDia', true, '2026-04-21 15:39:28.090922+00', '2026-04-21 15:39:28.090922+00');
INSERT INTO public.socios ("Id", "NombreEmpresa", "Slug", "Descripcion", "Especialidades", "Servicios", "RsWebsite", "RsFacebook", "RsLinkedin", "RsTwitter", "RsInstagram", "RsYoutube", "Telefono", "Direccion", "LogoUrl", "EmailContacto", "MapaUrl", "MarcasRepresenta", "EstadoFinanciero", "Habilitado", "CreatedAt", "UpdatedAt") VALUES ('36252670-6b2f-4be1-9906-89d332c05958', 'Unplug Studio', 'unplug-studio', 'Unplug Studio nace de un deseo de reinventarse y explorar nuevas metodologías de trabajo, que están en el ''Balance de trabajo en la vida'' y eso les permite a ellos proveerla información centralizada y la gran calidad de servicios digitales, permitiendo a sus clientes desconectarse de sus preocupaciones y convertir la tecnología es una herramienta que le permita cumplir sus metas.
INSERT INTO public.socios ("Id", "NombreEmpresa", "Slug", "Descripcion", "Especialidades", "Servicios", "RsWebsite", "RsFacebook", "RsLinkedin", "RsTwitter", "RsInstagram", "RsYoutube", "Telefono", "Direccion", "LogoUrl", "EmailContacto", "MapaUrl", "MarcasRepresenta", "EstadoFinanciero", "Habilitado", "CreatedAt", "UpdatedAt") VALUES ('76e54270-4eb3-4b13-a554-73fb60880011', 'TIGO EL SALVADOR', 'tigo', 'Compañía salvadoreña, comprometida a invertir en la transformación digital de El Salvador a través de productos y servicios innovadores. Tigo es la marca comercial de la empresa Millicom que tiene presencia en el país desde 1992 cuando invirtió en Telemóvil de El Salvador y desde entonces ocupa el puesto #1 en el país en servicios de tecnología móvil y ofrece servicios digitales integrales tales como comunicaciones móviles de voz, televisión por cable, internet de alta velocidad y servicios financieros móviles a más del 45% de la población.', '{Telecomunicaciones,"Internet de alta velocidad","Televisión por cable","Servicios móviles","Servicios financieros digitales"}', '{"Telefonía móvil","Internet residencial y empresarial","Televisión por suscripción","Servicios financieros móviles","Soluciones digitales integrales"}', 'https://www.tigo.com.sv/', 'https://www.facebook.com/tigosv', '', '', '', '', '2500-4600', 'Bulevar Santa Elena, Antiguo Cuscatlán, La Libertad, El Salvador', 'https://www.casatic.org/gallery\Socios\b33e5a34-9391-4dda-8b50-9d2bf20cf0dd.png ', 'msalinas@sc.tigo.com', '', '', 'AlDia', true, '2026-04-21 16:16:18.503367+00', '2026-04-21 16:16:18.503367+00');
INSERT INTO public.socios ("Id", "NombreEmpresa", "Slug", "Descripcion", "Especialidades", "Servicios", "RsWebsite", "RsFacebook", "RsLinkedin", "RsTwitter", "RsInstagram", "RsYoutube", "Telefono", "Direccion", "LogoUrl", "EmailContacto", "MapaUrl", "MarcasRepresenta", "EstadoFinanciero", "Habilitado", "CreatedAt", "UpdatedAt") VALUES ('35bcc944-08f4-4121-b0bc-b27c021ad53e', 'CONSORCIO INDUSTRIAL INDEPENDENCIA, S.A. DE C.V.', 'consisa', 'Consultores en Sistemas (Grupo CONSISA) es una empresa con 30 años de operación, con gean experiencia en el campo de la tecnología de información orientada a proveer soluciones de negocios. Además de su experiencia, proponen herramientas que les permitan agilizar sus procesos.', '{"Servicios educativos","Distribución de material didáctico","Comercialización de contenido educativo","Recursos educativos digitales","Gestión de contenidos educativos"}', '{"Importación de libros y materiales educativos","Distribución de recursos educativos","Comercialización de contenido digital educativo","Servicios de apoyo educativo","Gestión de proyectos educativos"}', 'http://www.consisa.com', 'https://www.facebook.com/GrupoConsisa', 'https://www.linkedin.com/company/grupo-consisa/?originalSubdomain=sv', '', '', '', '2505 6000', 'Dirección: Edificio Gran Plaza, Local 408 Boulevard del Hipódromo, col. San Benito San Salvador, El Salvador', 'https://www.casatic.org/gallery/Socios/f84f715e-d876-48d4-8cd3-1621e05a7583.png', 'info@consisa.com', 'https://www.google.com/maps/embed?pb=!1m18!1m12!1m3!1d242.27496661359126!2d-89.23556931339299!3d13.694239303776769!2m3!1f0!2f0!3f0!3m2!1i1024!2i768!4f13.1!3m3!1m2!1s0x8f63303a94183cd5%3A0xd6866b9ef77b784f!2sGrupo%20CONSISA%20El%20Salvador!5e0!3m2!1ses!2ssv!4v1773934631383!5m2!1ses!2ssv', '', 'AlDia', true, '2026-03-19 15:44:32.119688+00', '2026-04-21 17:44:34.603404+00');
